type ButtonVariant = NonNullable<
  VariantProps<typeof buttonVariants>["variant"]
>;

type ButtonSize = NonNullable<VariantProps<typeof buttonVariants>["size"]>;

type ButtonShape = NonNullable<VariantProps<typeof buttonVariants>["shape"]>;

type ButtonProps = Omit<
  React.ButtonHTMLAttributes<HTMLButtonElement>,
  "color" | "prefix" | "suffix"
> &
  VariantProps<typeof buttonVariants> & {
    loading?: boolean;
    sound?: SoundName | false;
    prefix?: React.ReactNode;
    suffix?: React.ReactNode;
  };

const ButtonShapeContext = React.createContext<ButtonShape | undefined>(
  undefined,
);

const buttonVariantSounds = {
  solid: "button.solid",
  soft: "button.soft",
  ghost: "button.ghost",
  outline: "button.outline",
} satisfies Record<ButtonVariant, SoundName>;

const buttonSpinnerSizes = {
  micro: "size-3",
  tiny: "size-3",
  small: "size-3.5",
  medium: "size-4",
  large: "size-4",
} satisfies Record<ButtonSize, string>;

const buttonPrefixSlotWidths = {
  micro: "0.75rem",
  tiny: "0.875rem",
  small: "1rem",
  medium: "1rem",
  large: "1rem",
} satisfies Record<ButtonSize, string>;

const buttonAffixGaps = {
  micro: "0.375rem",
  tiny: "0.375rem",
  small: "0.5rem",
  medium: "0.5rem",
  large: "0.5rem",
} satisfies Record<ButtonSize, string>;

const buttonSuffixPadding = {
  micro: "pr-1.5",
  tiny: "pr-2",
  small: "pr-2",
  medium: "",
  large: "",
} satisfies Record<ButtonSize, string>;

function Spinner({ className }: { className?: string }) {
  return (
    <span className={cn("relative inline-flex shrink-0", className)}>
      <svg
        className="size-full animate-spin motion-reduce:animate-none"
        viewBox="0 0 24 24"
        fill="none"
        aria-hidden="true"
      >
        <circle
          className="opacity-25"
          cx="12"
          cy="12"
          r="9"
          stroke="currentColor"
          strokeWidth="3"
        />

        <circle
          cx="12"
          cy="12"
          r="9"
          stroke="currentColor"
          strokeWidth="3"
          strokeLinecap="round"
          strokeDasharray="36 56"
          strokeDashoffset="8"
        />
      </svg>
    </span>
  );
}

function ButtonAffix({
  side,
  show,
  gap,
  width,
  replacing = false,
  replacement,
  children,
}: {
  side: "prefix" | "suffix";
  show: boolean;
  gap: string;
  width?: string;
  replacing?: boolean;
  replacement?: React.ReactNode;
  children: React.ReactNode;
}) {
  const isPrefix = side === "prefix";
  const hasReplacement = Boolean(replacement);
  const hasFixedWidth = isPrefix && Boolean(width);
  const showReplacement = hasReplacement && replacing;
  const showChildren = !hasReplacement || !replacing;

  return (
    <span
      data-slot={isPrefix ? "button-prefix" : "button-suffix"}
      data-visible={show ? "" : undefined}
      className={cn(
        "inline-flex shrink-0 items-center justify-center overflow-hidden",
        "transition-[width,max-width,opacity,margin] duration-200 ease-out",
        show ? "opacity-100" : "opacity-0",
      )}
      style={{
        width: hasFixedWidth ? (show ? width : "0px") : undefined,
        maxWidth: hasFixedWidth ? undefined : show ? "16rem" : "0px",
        marginRight: isPrefix && show ? gap : 0,
        marginLeft: !isPrefix && show ? gap : 0,
      }}
    >
      <span className="grid shrink-0 place-items-center">
        <span
          aria-hidden={!showChildren}
          className={cn(
            "col-start-1 row-start-1 inline-flex shrink-0 items-center justify-center",
            "transition-[opacity,scale] duration-200 ease-out",
            showChildren ? "scale-100 opacity-100" : "scale-90 opacity-0",
          )}
        >
          {children}
        </span>

        {hasReplacement && (
          <span
            aria-hidden={!showReplacement}
            className={cn(
              "col-start-1 row-start-1 inline-flex shrink-0 items-center justify-center",
              "transition-[opacity,scale] duration-200 ease-out",
              showReplacement ? "scale-100 opacity-100" : "scale-90 opacity-0",
            )}
          >
            {replacement}
          </span>
        )}
      </span>
    </span>
  );
}

function ButtonShapeProvider({
  children,
  shape,
}: {
  children: React.ReactNode;
  shape?: ButtonShape;
}) {
  return (
    <ButtonShapeContext.Provider value={shape}>
      {children}
    </ButtonShapeContext.Provider>
  );
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(function Button(
  {
    className,
    variant,
    color,
    size,
    shape,
    loading = false,
    sound,
    prefix,
    suffix,
    onClick,
    disabled,
    children,
    type = "button",
    ...props
  },
  ref,
) {
  const inheritedShape = React.useContext(ButtonShapeContext);
  const resolvedVariant = variant ?? "solid";
  const resolvedColor = color ?? "blue";
  const resolvedSize = size ?? "medium";
  const resolvedShape = shape ?? inheritedShape ?? "square";

  const isDisabled = Boolean(disabled);
  const isInteractionBlocked = isDisabled || loading;
  const hasLabel = Boolean(children);
  const hasPrefix = Boolean(prefix);
  const hasSuffix = Boolean(suffix);
  const shouldLoadInSuffix = loading && !hasPrefix && hasSuffix;
  const shouldLoadInPrefix = loading && !shouldLoadInSuffix;
  const showPrefix = shouldLoadInPrefix || hasPrefix;
  const showSuffix = shouldLoadInSuffix || hasSuffix;

  const resolvedSound =
    sound === undefined ? buttonVariantSounds[resolvedVariant] : sound;

  return (
    <button
      ref={ref}
      data-slot="button"
      data-loading={loading ? "" : undefined}
      data-disabled={isDisabled ? "" : undefined}
      type={type}
      className={cn(
        buttonVariants({
          variant: resolvedVariant,
          color: resolvedColor,
          size: resolvedSize,
          shape: resolvedShape,
          className,
        }),
        showSuffix && buttonSuffixPadding[resolvedSize],
      )}
      disabled={isDisabled}
      aria-disabled={loading && !isDisabled ? true : undefined}
      aria-busy={loading || undefined}
      onClick={(event) => {
        if (isInteractionBlocked) {
          event.preventDefault();
          return;
        }

        if (resolvedSound) {
          playSound(resolvedSound);
        }

        onClick?.(event);
      }}
      {...props}
    >
      <ButtonAffix
        side="prefix"
        show={showPrefix}
        gap={hasLabel ? buttonAffixGaps[resolvedSize] : "0px"}
        width={hasPrefix ? undefined : buttonPrefixSlotWidths[resolvedSize]}
        replacing={shouldLoadInPrefix}
        replacement={
          shouldLoadInPrefix ? (
            <Spinner className={buttonSpinnerSizes[resolvedSize]} />
          ) : undefined
        }
      >
        {prefix}
      </ButtonAffix>

      {children && (
        <span data-slot="button-label" className="inline-flex items-center">
          {children}
        </span>
      )}

      <ButtonAffix
        side="suffix"
        show={showSuffix}
        gap={hasLabel ? buttonAffixGaps[resolvedSize] : "0px"}
        replacing={shouldLoadInSuffix}
        replacement={
          shouldLoadInSuffix ? (
            <Spinner className={buttonSpinnerSizes[resolvedSize]} />
          ) : undefined
        }
      >
        {suffix}
      </ButtonAffix>
    </button>
  );
});

export { Button, ButtonShapeProvider, buttonVariants };

export type SoundName =
  | "button.solid"
  | "button.soft"
  | "button.ghost"
  | "button.outline"
  | "button.destructive"
  | "dialog.open"
  | "dialog.close"
  | "input.focus"
  | "input.unfocus"
  | "input.clear"
  | "success"
  | "error";

type SoundSettings = {
  enabled: boolean;
  volume: number;
};

const settings: SoundSettings = {
  enabled: true,
  volume: 1,
};

let audioContext: AudioContext | null = null;

function isMobileDevice() {
  if (typeof window === "undefined") return false;

  return (
    window.matchMedia("(pointer: coarse)").matches ||
    (typeof navigator !== "undefined" && navigator.maxTouchPoints > 0)
  );
}

function getAudioContext() {
  if (typeof window === "undefined") return null;

  audioContext ??= new AudioContext();

  return audioContext;
}

function playTone({
  frequency,
  endFrequency,
  duration,
  volume,
  type = "sine",
  envelope = "pluck",
}: {
  frequency: number;
  endFrequency?: number;
  duration: number;
  volume: number;
  type?: OscillatorType;
  envelope?: "pluck" | "swell" | "reverse";
}) {
  if (!settings.enabled) return;
  if (isMobileDevice()) return;

  const ctx = getAudioContext();
  if (!ctx) return;

  const oscillator = ctx.createOscillator();
  const gain = ctx.createGain();

  oscillator.type = type;
  oscillator.frequency.setValueAtTime(frequency, ctx.currentTime);
  if (endFrequency) {
    oscillator.frequency.exponentialRampToValueAtTime(
      endFrequency,
      ctx.currentTime + duration,
    );
  }

  gain.gain.setValueAtTime(0.0001, ctx.currentTime);

  if (envelope === "swell") {
    gain.gain.exponentialRampToValueAtTime(
      volume,
      ctx.currentTime + duration * 0.72,
    );
    gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + duration);
  } else if (envelope === "reverse") {
    gain.gain.exponentialRampToValueAtTime(volume, ctx.currentTime + 0.002);
    gain.gain.exponentialRampToValueAtTime(
      volume * 0.38,
      ctx.currentTime + duration * 0.32,
    );
    gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + duration);
  } else {
    gain.gain.exponentialRampToValueAtTime(volume, ctx.currentTime + 0.004);
    gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + duration);
  }

  oscillator.connect(gain);
  gain.connect(ctx.destination);

  oscillator.start(ctx.currentTime);
  oscillator.stop(ctx.currentTime + duration);
}

function blip(frequency: number, volume: number) {
  playTone({
    frequency,
    duration: 0.035,
    volume,
    type: "sine",
  });
}

function playButtonSolidSound() {
  playTone({
    frequency: 420,
    duration: 0.045,
    volume: 0.028 * settings.volume,
    type: "triangle",
  });
}

const sounds: Record<SoundName, () => void> = {
  "button.solid": playButtonSolidSound,

  "button.soft": () => {
    playTone({
      frequency: 520,
      duration: 0.05,
      volume: 0.018 * settings.volume,
      type: "sine",
    });
  },

  "button.ghost": () => {
    playTone({
      frequency: 760,
      duration: 0.025,
      volume: 0.012 * settings.volume,
      type: "sine",
    });
  },

  "button.outline": () => {
    playTone({
      frequency: 620,
      duration: 0.035,
      volume: 0.02 * settings.volume,
      type: "triangle",
    });
  },

  "button.destructive": () => {
    playTone({
      frequency: 220,
      duration: 0.065,
      volume: 0.025 * settings.volume,
      type: "triangle",
    });
  },

  "dialog.open": () => {
    playTone({
      frequency: 360,
      endFrequency: 520,
      duration: 0.07,
      volume: 0.018 * settings.volume,
      type: "triangle",
    });
  },

  "dialog.close": () => {
    playTone({
      frequency: 420,
      endFrequency: 260,
      duration: 0.06,
      volume: 0.014 * settings.volume,
      type: "triangle",
    });
  },

  "input.focus": playButtonSolidSound,

  "input.unfocus": () => {
    playTone({
      frequency: 300,
      endFrequency: 240,
      duration: 0.07,
      volume: 0.014 * settings.volume,
      type: "triangle",
    });
  },

  "input.clear": () => {
    playTone({
      frequency: 640,
      endFrequency: 420,
      duration: 0.035,
      volume: 0.008 * settings.volume,
      type: "triangle",
    });
  },

  success: () => {
    blip(520, 0.022 * settings.volume);

    window.setTimeout(() => {
      blip(780, 0.022 * settings.volume);
    }, 55);
  },

  error: () => {
    playTone({
      frequency: 180,
      duration: 0.08,
      volume: 0.026 * settings.volume,
      type: "triangle",
    });
  },
};

export function playSound(sound: SoundName) {
  if (isMobileDevice()) return;
  sounds[sound]?.();
}

export function configureSounds(options: Partial<SoundSettings>) {
  if (typeof options.enabled === "boolean") {
    settings.enabled = options.enabled;
  }

  if (typeof options.volume === "number") {
    settings.volume = Math.max(0, Math.min(options.volume, 1));
  }
}

export function enableSounds() {
  settings.enabled = true;
}

export function disableSounds() {
  settings.enabled = false;
}

export function setSoundVolume(volume: number) {
  settings.volume = Math.max(0, Math.min(volume, 1));
}

export function getSoundSettings() {
  return { ...settings };
}
